const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { buildSchema } = require('graphql');
const { Client } = require('pg');

const schema = buildSchema(`
  type Query {
    post(id: Int!): Post
    posts: [Post]
  }

  type Post {
    id: Int
    title: String
    body: String
    author: Author
  }

  type Author {
    id: Int
    name: String
  }
`);

const root = {
  post: async ({ id }) => {
    const client = new Client();
    await client.connect();
    const post = await client.query('SELECT * FROM posts WHERE id = $1', [id]);
    await client.end();
    return post.rows[0];
  },

  posts: async () => {
    const client = new Client();
    await client.connect();
    const posts = await client.query('SELECT * FROM posts');
    await client.end();
    return posts.rows;
  },

  author: async ({ id }) => {
    const client = new Client();
    await client.connect();
    const author = await client.query('SELECT * FROM authors WHERE id = $1', [id]);
    await client.end();
    return author.rows[0];
  }
};

const app = express();
app.use('/graphql', graphqlHTTP({
  schema: schema,
  rootValue: root,
  graphiql: true,
}));
app.listen(4000);